     1|/**
     2| * live-evidence.ts — End-to-end deployment evidence checker for IVX.
     3| *
     4| * Orchestrates all evidence tool checks:
     5| *   - GitHub Evidence (commit SHA via /version)
     6| *   - Render Evidence (/tool/render-status)
     7| *   - Health Evidence (/health)
     8| *   - Chat Evidence (send/receive/persist)
     9| *   - Supabase Evidence (tables/counts/insert/read)
    10| *   - Frontend Evidence (self-check)
    11| *
    12| * Returns a structured EvidenceReport with individual tool results plus an
    13| * aggregated FINAL_STATUS.
    14| */
    15|
    16|import { getDirectApiBaseUrl } from '@/lib/api-base';
    17|import { supabase } from '@/lib/supabase';
    18|
    19|// ---------------------------------------------------------------------------
    20|// Types
    21|// ---------------------------------------------------------------------------
    22|
    23|export type EvidenceStatus = 'ok' | 'fail' | 'checking' | 'skipped';
    24|
    25|export type EvidenceFinalStatus =
    26|  | 'COMPLETE'
    27|  | 'BLOCKED'
    28|  | 'LOCAL ONLY'
    29|  | 'UNVERIFIED';
    30|
    31|export interface StreamEvent {
    32|  id: string;
    33|  tool: string;
    34|  phase: 'started' | 'completed' | 'error';
    35|  message: string;
    36|  timestamp: string;
    37|  detail?: string;
    38|}
