   100|
   101|export interface LiveEvidenceReport {
   102|  timestamp: string;
   103|  github: GitHubEvidenceResult;
   104|  render: RenderEvidenceResult;
   105|  health: HealthEvidenceResult;
   106|  chat: ChatEvidenceResult;
   107|  supabase: SupabaseEvidenceResult;
