   118|
   119|const API_BASE = getDirectApiBaseUrl();
   120|
   121|function generateId(): string {
   122|  return `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
   123|}
   124|
   125|function parseError(err: unknown): string {
   126|  if (err instanceof Error) return err.message;
   127|  return String(err ?? 'Unknown error');
   128|}
   129|
   130|async function fetchJSON(
   131|  url: string,
   132|  options: RequestInit = {},
   133|): Promise<{ ok: boolean; data: Record<string, unknown>; status: number; error: string }> {
   134|  try {
   135|    const response = await fetch(url, {
   136|      ...options,
   137|      headers: {
   138|        'Content-Type': 'application/json',
   139|        ...(options.headers as Record<string, string>),
   140|      },
   141|    });
   142|    const text = await response.text();
   143|    let data: Record<string, unknown> = {};
   144|    try {
   145|      data = JSON.parse(text);
   146|    } catch {
   147|      data = { raw: text.slice(0, 500) };
   148|    }
   149|    return {
   150|      ok: response.ok,
   151|      data,
   152|      status: response.status,
   153|      error: response.ok ? '' : (data.error as string) || `HTTP ${response.status}`,
   154|    };
   155|  } catch (err) {
   156|    return {
   157|      ok: false,
   158|      data: {},
   159|      status: 0,
   160|      error: parseError(err),
   161|    };
   162|  }
   163|}
