   169|/** Fetches GitHub commit SHA from the live backend /version endpoint. */
   170|async function checkGitHubEvidence(
   171|  pushEvent: (event: StreamEvent) => void,
   172|): Promise<GitHubEvidenceResult> {
   173|  pushEvent({
   174|    id: generateId(),
   175|    tool: 'GitHub',
   176|    phase: 'started',
   177|    message: 'Fetching GitHub commit info from /version',
   178|    timestamp: new Date().toISOString(),
   179|  });
   180|
   181|  try {
   182|    const { ok, data, error } = await fetchJSON(`${API_BASE}/version`);
   183|
   184|    if (!ok) {
   185|      pushEvent({
   186|        id: generateId(),
   187|        tool: 'GitHub',
   188|        phase: 'error',
   189|        message: `GitHub check failed: ${error}`,
   190|        timestamp: new Date().toISOString(),
   191|        detail: error,
   192|      });
   193|      return {
   194|        status: 'fail',
   195|        repo: 'ibb142/rork-ivxholding--1',
   196|        branch: '',
   197|        latestCommitSha: '',
   198|        commitShort: '',
   199|        commitTimestamp: '',
   200|        error,
   201|      };
   202|    }
   203|
   204|    const result: GitHubEvidenceResult = {
   205|      status: 'ok',
   206|      repo: 'ibb142/rork-ivxholding--1',
   207|      branch: 'main',
   208|      latestCommitSha: (data.commit as string) || '',
   209|      commitShort: (data.commitShort as string) || '',
   210|      commitTimestamp: (data.bootTime as string) || (data.timestamp as string) || '',
   211|    };
   212|
   213|    pushEvent({
   214|      id: generateId(),
   215|      tool: 'GitHub',
   216|      phase: 'completed',
   217|      message: `GitHub commit: ${result.commitShort}`,
   218|      timestamp: new Date().toISOString(),
   219|      detail: result.latestCommitSha,
   220|    });
   221|
   222|    return result;
   223|  } catch (err) {
   224|    const msg = parseError(err);
   225|    pushEvent({
   226|      id: generateId(),
   227|      tool: 'GitHub',
   228|      phase: 'error',
   229|      message: `GitHub check exception: ${msg}`,
   230|      timestamp: new Date().toISOString(),
   231|      detail: msg,
   232|    });
   233|    return {
   234|      status: 'fail',
   235|      repo: 'ibb142/rork-ivxholding--1',
   236|      branch: '',
   237|      latestCommitSha: '',
   238|      commitShort: '',
   239|      commitTimestamp: '',
   240|      error: msg,
   241|    };
   242|  }
