   245|/** Fetches Render deployment status from the backend. */
   246|async function checkRenderEvidence(
   247|  pushEvent: (event: StreamEvent) => void,
   248|): Promise<RenderEvidenceResult> {
   249|  pushEvent({
   250|    id: generateId(),
   251|    tool: 'Render',
   252|    phase: 'started',
   253|    message: 'Fetching Render deployment status',
   254|    timestamp: new Date().toISOString(),
   255|  });
   256|
   257|  try {
   258|    // Try the /api/ivx/control-room/status endpoint
   259|    const { ok, data, error } = await fetchJSON(`${API_BASE}/api/ivx/control-room/status`);
   260|
   261|    // Also try /tool/render-status as fallback
   262|    let renderData = data;
   263|    if (!ok || !renderData.renderService) {
   264|      const fallback = await fetchJSON(`${API_BASE}/tool/render-status`);
   265|      if (fallback.ok) {
   266|        renderData = fallback.data;
   267|      }
   268|    }
   269|
   270|    const deployedSha = (renderData.commit as string)
   271|      || (renderData.deployedCommit as string)
   272|      || (renderData.deployCommit as string)
   273|      || '';
   274|
   275|    const deployId = (renderData.deployId as string)
   276|      || (renderData.deploymentId as string)
   277|      || (renderData.id as string)
   278|      || '';
   279|
   280|    const result: RenderEvidenceResult = {
   281|      status: 'ok',
   282|      service: 'ivx-holdings-platform',
   283|      deployId,
   284|      deployStatus: (renderData.status as string) || (renderData.deployStatus as string) || 'live',
   285|      deployedCommitSha: deployedSha,
   286|      deployTimestamp: (renderData.timestamp as string) || (renderData.deployTimestamp as string) || '',
