   323|/** Tests the /health endpoint. */
   324|async function checkHealthEvidence(
   325|  pushEvent: (event: StreamEvent) => void,
   326|): Promise<HealthEvidenceResult> {
   327|  pushEvent({
   328|    id: generateId(),
   329|    tool: 'Health',
   330|    phase: 'started',
   331|    message: 'Testing /health endpoint',
   332|    timestamp: new Date().toISOString(),
   333|  });
   334|
   335|  const start = performance.now();
   336|
   337|  try {
   338|    const { ok, data, status } = await fetchJSON(`${API_BASE}/health`);
   339|    const elapsed = Math.round(performance.now() - start);
   340|
   341|    if (!ok) {
   342|      pushEvent({
   343|        id: generateId(),
   344|        tool: 'Health',
   345|        phase: 'error',
   346|        message: `/health returned HTTP ${status}`,
   347|        timestamp: new Date().toISOString(),
   348|      });
   349|      return {
   350|        status: 'fail',
   351|        httpStatus: status,
   352|        responseBody: data,
   353|        responseTimeMs: elapsed,
   354|        liveCommitSha: '',
   355|        error: `HTTP ${status}`,
   356|      };
   357|    }
   358|
   359|    const commit = (data.commit as string) || '';
   360|
   361|    pushEvent({
   362|      id: generateId(),
   363|      tool: 'Health',
   364|      phase: 'completed',
   365|      message: `/health OK (${elapsed}ms), commit: ${(data.commitShort as string) || commit.slice(0, 8)}`,
   366|      timestamp: new Date().toISOString(),
   367|      detail: commit,
   368|    });
   369|
   370|    return {
   371|      status: 'ok',
   372|      httpStatus: status,
   373|      responseBody: data,
   374|      responseTimeMs: elapsed,
   375|      liveCommitSha: commit,
   376|    };
   377|  } catch (err) {
   378|    const msg = parseError(err);
   379|    const elapsed = Math.round(performance.now() - start);
   380|    pushEvent({
   381|      id: generateId(),
   382|      tool: 'Health',
   383|      phase: 'error',
   384|      message: `Health check exception: ${msg}`,
   385|      timestamp: new Date().toISOString(),
   386|      detail: msg,
   387|    });
   388|    return {
   389|      status: 'fail',
   390|      httpStatus: 0,
   391|      responseBody: {},
   392|      responseTimeMs: elapsed,
   393|      liveCommitSha: '',
   394|      error: msg,
   395|    };
   396|  }
