   399|/** Sends a test chat message and verifies persistence. */
   400|async function checkChatEvidence(
   401|  pushEvent: (event: StreamEvent) => void,
   402|): Promise<ChatEvidenceResult> {
   403|  pushEvent({
   404|    id: generateId(),
   405|    tool: 'Chat',
   406|    phase: 'started',
   407|    message: 'Sending test chat message',
   408|    timestamp: new Date().toISOString(),
   409|  });
   410|
   411|  try {
   412|    const testUsername = `evidence-bot-${Date.now()}`;
   413|    const testText = `IVX deployment evidence check — ${new Date().toISOString()}`;
   414|
   415|    // Send message via REST API
   416|    const sendResult = await fetchJSON(`${API_BASE}/api/public/send-message`, {
   417|      method: 'POST',
   418|      body: JSON.stringify({
   419|        roomId: 'main-room',
   420|        username: testUsername,
   421|        text: testText,
   422|        source: 'user',
   423|      }),
   424|    });
   425|
   426|    if (!sendResult.ok) {
   427|      pushEvent({
   428|        id: generateId(),
   429|        tool: 'Chat',
   430|        phase: 'error',
   431|        message: `Chat send failed: ${sendResult.error}`,
   432|        timestamp: new Date().toISOString(),
   433|        detail: sendResult.error,
   434|      });
   435|      return {
   436|        status: 'fail',
   437|        conversationId: '',
   438|        messageIds: [],
   439|        assistantReplied: false,
   440|        messageSaved: false,
   441|        error: sendResult.error,
   442|      };
   443|    }
   444|
   445|    const sendData = sendResult.data;
   446|    const assistantReplied = !!(sendData.assistantMessage || sendData.ai);
   447|    const userMsgId = (sendData.message as Record<string, unknown>)?.id as string || '';
   448|    const assistantMsgId = (sendData.assistantMessage as Record<string, unknown>)?.id as string || '';
   449|    const messageIds = [userMsgId, assistantMsgId].filter(Boolean);
   450|
   451|    // Verify persistence: re-fetch messages
   452|    let messageSaved = false;
   453|    try {
   454|      const msgsResult = await fetchJSON(
   455|        `${API_BASE}/api/public/messages?roomId=main-room&limit=5`,
   456|      );
   457|      if (msgsResult.ok) {
   458|        const messages = msgsResult.data.messages as Array<Record<string, unknown>> || [];
   459|        messageSaved = messages.some((m) => m.id === userMsgId);
   460|      }
   461|    } catch {
   462|      // Non-fatal: persistence check failed but send succeeded
   463|    }
   464|
   465|    pushEvent({
   466|      id: generateId(),
   467|      tool: 'Chat',
   468|      phase: 'completed',
   469|      message: `Chat send OK, assistant replied: ${assistantReplied}, saved: ${messageSaved}`,
   470|      timestamp: new Date().toISOString(),
   471|    });
   472|
   473|    return {
   474|      status: 'ok',
   475|      conversationId: 'main-room',
   476|      messageIds,
   477|      assistantReplied,
   478|      messageSaved,
   479|    };
   480|  } catch (err) {
   481|    const msg = parseError(err);
   482|    pushEvent({
   483|      id: generateId(),
   484|      tool: 'Chat',
   485|      phase: 'error',
   486|      message: `Chat check exception: ${msg}`,
   487|      timestamp: new Date().toISOString(),
   488|      detail: msg,
   489|    });
   490|    return {
   491|      status: 'fail',
   492|      conversationId: '',
   493|      messageIds: [],
   494|      assistantReplied: false,
   495|      messageSaved: false,
   496|      error: msg,
   497|    };
   498|  }
