   619|    pushEvent({
   620|      id: generateId(),
   621|      tool: 'Frontend',
   622|      phase: 'completed',
   623|      message: `Frontend self-check OK, API reachable: ${healthCheck.ok}`,
   624|      timestamp: new Date().toISOString(),
