   635|  } catch (err) {
   636|    const msg = parseError(err);
   637|    pushEvent({
   638|      id: generateId(),
   639|      tool: 'Frontend',
   640|      phase: 'error',
   641|      message: `Frontend check failed: ${msg}`,
   642|      timestamp: new Date().toISOString(),
   643|      detail: msg,
   644|    });
   645|    return {
   646|      status: 'fail',
   647|      chatRoomLoads: false,
   648|      ownerChatWorks: false,
   649|      monitorLoads: true,
   650|      noTypeError: true,
   651|      error: msg,
   652|    };
   653|  }
