   659|
   660|export interface RunEvidenceOptions {
   661|  /** Run GitHub check */
   662|  github?: boolean;
   663|  /** Run Render check */
   664|  render?: boolean;
   665|  /** Run Health check */
   666|  health?: boolean;
   667|  /** Run Chat check */
   668|  chat?: boolean;
   669|  /** Run Supabase check */
   670|  supabase?: boolean;
   671|  /** Run Frontend check */
   672|  frontend?: boolean;
