   674|
   675|/** Runs the full evidence check suite. Returns a LiveEvidenceReport. */
   676|export async function runFullEvidenceCheck(
   677|  options: RunEvidenceOptions = {},
   678|  onStream?: (event: StreamEvent) => void,
   679|): Promise<LiveEvidenceReport> {
   680|  const stream: StreamEvent[] = [];
   681|
   682|  const pushEvent = (event: StreamEvent) => {
   683|    stream.push(event);
   684|    onStream?.(event);
   685|  };
   686|
   687|  const opts = {
   688|    github: true,
   689|    render: true,
   690|    health: true,
   691|    chat: true,
   692|    supabase: true,
   693|    frontend: true,
