  freshness: DataFreshness;
  github: GitHubEvidenceResult;
  render: RenderEvidenceResult;
  health: HealthEvidenceResult;
  chat: ChatEvidenceResult;
  supabase: SupabaseEvidenceResult;
  frontend: FrontendEvidenceResult;
  stream: StreamEvent[];
