  Render: '#8B5CF6',
  Health: '#22C55E',
  Chat: '#3B82F6',
  Supabase: '#22C55E',
  Frontend: '#06B6D4',
};

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

function StatusBadge({ status }: { status: EvidenceStatus }) {
  const cfg = STATUS_CONFIG[status];
  const Icon = cfg.icon;
  return (
    <View style={[statusBadgeStyles.badge, { backgroundColor: cfg.color + '1A' }]}>
