  );
}

const toolCardStyles = StyleSheet.create({
  card: {
    backgroundColor: Colors.surfaceElevated,
    borderRadius: 12,
    borderWidth: 0.5,
    borderColor: Colors.surfaceBorder,
    padding: CARD_PADDING,
    marginBottom: CARD_GAP,
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 10,
  },
  titleRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 10,
  },
  iconBox: {
    width: 32,
    height: 32,
    borderRadius: 8,
    alignItems: 'center',
    justifyContent: 'center',
  },
  toolName: {
    fontSize: 15,
    fontWeight: '700' as const,
    color: Colors.text,
  },
});

function EvidenceRow({ label, value, mono, color }: { label: string; value: string; mono?: boolean; color?: string }) {
  if (!value && value !== '0') return null;
  return (
    <View style={evidenceRowStyles.row}>
      <Text style={evidenceRowStyles.label}>{label}</Text>
      <Text
        style={[
          evidenceRowStyles.value,
          mono && evidenceRowStyles.mono,
          color ? { color } : undefined,
        ]}
        numberOfLines={1}
      >
        {value}
      </Text>
    </View>
  );
}

const evidenceRowStyles = StyleSheet.create({
  row: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingVertical: 4,
  },
  label: {
    fontSize: 12,
    color: Colors.textTertiary,
    flex: 1,
  },
  value: {
    fontSize: 12,
    color: Colors.textSecondary,
    fontWeight: '600' as const,
    flex: 1.5,
    textAlign: 'right' as const,
  },
  mono: {
    fontFamily: Platform.select({ ios: 'Menlo', default: 'monospace' }),
    fontSize: 11,
    color: Colors.gold,
  },
});

function MatchBadge({ matches }: { matches: boolean }) {
  return (
    <View
      style={[
        matchBadgeStyles.badge,
        { backgroundColor: matches ? 'rgba(34,197,94,0.12)' : 'rgba(239,68,68,0.12)' },
      ]}
    >
      {matches ? (
        <CheckCircle size={10} color="#22C55E" strokeWidth={3} />
      ) : (
        <XCircle size={10} color="#EF4444" strokeWidth={3} />
      )}
      <Text
        style={[
          matchBadgeStyles.text,
          { color: matches ? '#22C55E' : '#EF4444' },
        ]}
      >
        {matches ? 'MATCH' : 'MISMATCH'}
      </Text>
    </View>
  );
}

const matchBadgeStyles = StyleSheet.create({
  badge: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 4,
    paddingHorizontal: 8,
    paddingVertical: 3,
    borderRadius: 6,
    alignSelf: 'flex-start',
  },
  text: {
    fontSize: 10,
    fontWeight: '800' as const,
    letterSpacing: 0.4,
  },
});

function StreamLogItem({ event }: { event: StreamEvent }) {
  const iconColor =
    event.phase === 'error' ? '#EF4444' :
    event.phase === 'completed' ? '#22C55E' :
    '#F59E0B';

  const ToolIcon = TOOL_ICONS[event.tool] || Activity;

  return (
    <View style={streamLogStyles.row}>
      <View style={[streamLogStyles.dot, { backgroundColor: iconColor }]} />
      <ToolIcon size={12} color={TOOL_COLORS[event.tool] || Colors.textTertiary} strokeWidth={2} />
      <View style={streamLogStyles.textCol}>
        <Text style={streamLogStyles.message} numberOfLines={2}>
          {event.message}
        </Text>
        {event.detail ? (
          <Text style={streamLogStyles.detail} numberOfLines={1}>
            {event.detail}
          </Text>
        ) : null}
      </View>
      <Text style={streamLogStyles.time}>
        {new Date(event.timestamp).toLocaleTimeString('en-US', { hour12: false })}
      </Text>
    </View>
  );
}

const streamLogStyles = StyleSheet.create({
  row: {
    flexDirection: 'row',
    alignItems: 'flex-start',
    gap: 8,
    paddingVertical: 6,
    paddingHorizontal: 2,
    borderBottomWidth: 0.5,
    borderBottomColor: Colors.surfaceBorder,
  },
  dot: {
    width: 6,
    height: 6,
    borderRadius: 3,
    marginTop: 5,
  },
  textCol: {
    flex: 1,
  },
  message: {
    fontSize: 11,
    color: Colors.textSecondary,
    lineHeight: 15,
  },
  detail: {
    fontSize: 10,
    color: Colors.textTertiary,
    fontFamily: Platform.select({ ios: 'Menlo', default: 'monospace' }),
    marginTop: 1,
  },
