          icon={RefreshCw}
          onPress={runAllChecks}
          disabled={checking}
          variant="primary"
        />
      </View>

      {/* Row 1: verify + deploy */}
      <View style={liveWorkStyles.buttonGrid}>
        <ActionButton
          label="Verify GitHub"
          icon={GitBranch}
          onPress={() => runToolCheck('github')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
        <ActionButton
          label="Verify Render"
          icon={Cloud}
          onPress={() => runToolCheck('render')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
      </View>

      {/* Row 2: chat + supabase */}
      <View style={liveWorkStyles.buttonGrid}>
        <ActionButton
          label="Test Chat Room"
          icon={MessageCircle}
          onPress={() => runToolCheck('chat')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
        <ActionButton
          label="Test Supabase"
          icon={Database}
          onPress={() => runToolCheck('supabase')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
      </View>

      {/* Row 3: health + frontend */}
      <View style={liveWorkStyles.buttonGrid}>
        <ActionButton
          label="Verify Health"
          icon={Activity}
          onPress={() => runToolCheck('health')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
        <ActionButton
          label="Verify Frontend"
          icon={Monitor}
          onPress={() => runToolCheck('frontend')}
          disabled={checkingTool !== null}
          variant="secondary"
        />
      </View>

      {/* Export row */}
      <View style={liveWorkStyles.buttonGrid}>
        <ActionButton
          label="Export JSON"
          icon={Download}
          onPress={handleExportJSON}
          disabled={!report}
          variant="export"
        />
        <ActionButton
          label="Copy Report"
          icon={Copy}
          onPress={handleCopyReport}
          disabled={!report}
          variant="export"
        />
      </View>

      {/* Auto-refresh toggle */}
      <View style={liveWorkStyles.buttonRow}>
        <TouchableOpacity
          style={[
            actionButtonStyles.button,
            actionButtonStyles.secondary,
            { flex: 0, paddingHorizontal: 20 },
          ]}
          onPress={() => setAutoRefresh(!autoRefresh)}
          activeOpacity={0.7}
        >
          <Timer size={14} color={autoRefresh ? '#22C55E' : Colors.textTertiary} strokeWidth={2.2} />
          <Text style={[actionButtonStyles.label, { color: autoRefresh ? '#22C55E' : Colors.textTertiary }]}>
            Auto-Refresh: {autoRefresh ? 'ON' : 'OFF'}
          </Text>
        </TouchableOpacity>
      </View>

      {checking && (
        <View style={liveWorkStyles.checkingBanner}>
          <ActivityIndicator size="small" color={Colors.gold} />
          <Text style={liveWorkStyles.checkingText}>
            {checkingTool ? `Checking ${checkingTool}...` : 'Running full evidence check...'}
          </Text>
        </View>
      )}
    </View>
  );

  return (
    <SafeAreaView style={screenStyles.root} edges={['top']}>
      <Stack.Screen options={{ headerShown: false }} />
      <View style={screenStyles.header}>
        <TouchableOpacity
          style={screenStyles.backButton}
          onPress={() => router.back()}
          activeOpacity={0.7}
        >
          <ArrowLeft size={20} color={Colors.text} strokeWidth={2} />
        </TouchableOpacity>
        <View style={screenStyles.headerCenter}>
          <Text style={screenStyles.headerTitle}>Live Evidence</Text>
          <Text style={screenStyles.headerSubtitle}>IVX Deployment Dashboard</Text>
        </View>
        <TouchableOpacity
          style={screenStyles.refreshButton}
          onPress={runAllChecks}
          disabled={checking}
          activeOpacity={0.7}
        >
          <RefreshCw size={18} color={Colors.gold} strokeWidth={2.2} />
        </TouchableOpacity>
      </View>

      <ScrollView
        ref={scrollRef}
        style={screenStyles.scroll}
        contentContainerStyle={screenStyles.scrollContent}
        showsVerticalScrollIndicator={false}
      >
        {renderCommitMatchSection()}
        {renderMonitorSection()}
        {renderHistorySection()}
        {renderStreamSection()}
        {renderLiveWorkSection()}

        <View style={screenStyles.footer} />
      </ScrollView>
    </SafeAreaView>
  );
}

// ---------------------------------------------------------------------------
// Styles
// ---------------------------------------------------------------------------

